  1→import {
  2→  createContext,
  3→  useState,
  4→  useEffect,
  5→  useCallback,
  6→  type ReactNode,
  7→} from 'react';
  8→import { useAuth } from '../hooks/useAuth';
  9→import { supabase } from '../lib/supabase';
 10→import {
 11→  initOneSignal,
 12→  isOneSignalReady,
 13→  promptForPush,
 14→  getPlayerId,
 15→  setExternalUserId,
 16→  addTag,
 17→  removeTag,
 18→} from '../lib/onesignal';
 19→import OneSignal from 'react-onesignal';
 20→
 21→interface PushContextValue {
 22→  isSupported: boolean;
 23→  isPermissionGranted: boolean;
 24→  isSubscribed: boolean;
 25→  playerId: string | null;
 26→  loading: boolean;
 27→  requestPermission: () => Promise<boolean>;
 28→  subscribeToMerchant: (merchantId: string) => Promise<void>;
 29→  unsubscribeFromMerchant: (merchantId: string) => Promise<void>;
 30→}
 31→
 32→export const PushContext = createContext<PushContextValue>({
 33→  isSupported: false,
 34→  isPermissionGranted: false,
 35→  isSubscribed: false,
 36→  playerId: null,
 37→  loading: true,
 38→  requestPermission: async () => false,
 39→  subscribeToMerchant: async () => {},
 40→  unsubscribeFromMerchant: async () => {},
 41→});
 42→
 43→export function PushProvider({ children }: { children: ReactNode }) {
 44→  const { user, isAuthenticated } = useAuth();
 45→  const [isSupported] = useState(() => 'Notification' in window && 'serviceWorker' in navigator);
 46→  const [isPermissionGranted, setIsPermissionGranted] = useState(false);
 47→  const [isSubscribed, setIsSubscribed] = useState(false);
 48→  const [playerId, setPlayerId] = useState<string | null>(null);
 49→  const [loading, setLoading] = useState(true);
 50→
 51→  // Initialize OneSignal when user is authenticated
 52→  useEffect(() => {
 53→    if (!isAuthenticated || !user || !isSupported) {
 54→      setLoading(false);
 55→      return;
 56→    }
 57→
 58→    async function setup() {
 59→      try {
 60→        await initOneSignal();
 61→
 62→        if (!isOneSignalReady()) {
 63→          setLoading(false);
 64→          return;
 65→        }
 66→
 67→        await setExternalUserId(user!.id);
 68→
 69→        const permission = OneSignal.Notifications.permission;
 70→        setIsPermissionGranted(permission);
 71→
 72→        if (permission) {
 73→          const pid = await getPlayerId();
 74→          setPlayerId(pid);
 75→
 76→          if (pid) {
 77→            await registerPlayerInDb(user!.id, pid);
 78→            setIsSubscribed(true);
 79→          }
 80→        }
 81→      } catch (err) {
 82→        console.warn('OneSignal init error:', err);
 83→      }
 84→      setLoading(false);
 85→    }
 86→
 87→    setup();
 88→  }, [isAuthenticated, user, isSupported]);
 89→
 90→  // Listen for permission changes
 91→  useEffect(() => {
 92→    if (!isOneSignalReady()) return;
 93→
 94→    const handlePermissionChange = (granted: boolean) => {
 95→      setIsPermissionGranted(granted);
 96→      if (!granted && user) {
 97→        deactivateSubscription(user.id);
 98→        setIsSubscribed(false);
 99→        setPlayerId(null);
100→      }
101→    };
102→
103→    OneSignal.Notifications.addEventListener('permissionChange', handlePermissionChange);
104→    return () => {
105→      OneSignal.Notifications.removeEventListener('permissionChange', handlePermissionChange);
106→    };
107→  }, [user]);
108→
109→  const requestPermission = useCallback(async (): Promise<boolean> => {
110→    if (!isOneSignalReady()) return false;
111→
112→    const granted = await promptForPush();
113→    setIsPermissionGranted(granted);
114→
115→    if (granted && user) {
116→      const pid = await getPlayerId();
117→      setPlayerId(pid);
118→      if (pid) {
119→        await registerPlayerInDb(user.id, pid);
120→        setIsSubscribed(true);
121→      }
122→    }
123→
124→    return granted;
125→  }, [user]);
126→
127→  const subscribeToMerchant = useCallback(async (merchantId: string) => {
128→    await addTag(`merchant_${merchantId}`, 'true');
129→  }, []);
130→
131→  const unsubscribeFromMerchant = useCallback(async (merchantId: string) => {
132→    await removeTag(`merchant_${merchantId}`);
133→  }, []);
134→
135→  return (
136→    <PushContext.Provider
137→      value={{
138→        isSupported,
139→        isPermissionGranted,
140→        isSubscribed,
141→        playerId,
142→        loading,
143→        requestPermission,
144→        subscribeToMerchant,
145→        unsubscribeFromMerchant,
146→      }}
147→    >
148→      {children}
149→    </PushContext.Provider>
150→  );
151→}
152→
153→// --- DB helpers ---
154→
155→async function registerPlayerInDb(profileId: string, playerId: string) {
156→  const { data: existing } = await supabase
157→    .from('onesignal_subscriptions')
158→    .select('id, is_active')
159→    .eq('player_id', playerId)
160→    .maybeSingle();
161→
162→  if (existing) {
163→    if (!existing.is_active) {
164→      await supabase
165→        .from('onesignal_subscriptions')
166→        .update({ is_active: true })
167→        .eq('id', existing.id);
168→    }
169→  } else {
170→    await supabase.from('onesignal_subscriptions').insert({
171→      profile_id: profileId,
172→      player_id: playerId,
173→      device_type: 'web',
174→      is_active: true,
175→    });
176→  }
177→}
178→
179→async function deactivateSubscription(profileId: string) {
180→  await supabase
181→    .from('onesignal_subscriptions')
182→    .update({ is_active: false })
183→    .eq('profile_id', profileId)
184→    .eq('device_type', 'web');
185→}
