  1→import { useState, useEffect } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { CustomerStats } from '@astrolab/shared';
  5→
  6→interface UseCustomerStatsReturn {
  7→  stats: CustomerStats;
  8→  loading: boolean;
  9→  error: string | null;
 10→}
 11→
 12→const defaultStats: CustomerStats = {
 13→  total_cards: 0,
 14→  total_points_all: 0,
 15→  total_scans: 0,
 16→  last_scan_at: null,
 17→  active_offers: 0,
 18→};
 19→
 20→export function useCustomerStats(): UseCustomerStatsReturn {
 21→  const { user } = useAuth();
 22→  const [stats, setStats] = useState<CustomerStats>(defaultStats);
 23→  const [loading, setLoading] = useState(true);
 24→  const [error, setError] = useState<string | null>(null);
 25→
 26→  useEffect(() => {
 27→    if (!user) {
 28→      setLoading(false);
 29→      return;
 30→    }
 31→
 32→    async function fetchStats() {
 33→      setLoading(true);
 34→
 35→      const { data: customer } = await supabase
 36→        .from('customers')
 37→        .select('id')
 38→        .eq('profile_id', user!.id)
 39→        .single();
 40→
 41→      if (!customer) {
 42→        setLoading(false);
 43→        return;
 44→      }
 45→
 46→      // Requetes en parallele
 47→      const [cardsRes, scansRes, offersRes] = await Promise.all([
 48→        supabase
 49→          .from('loyalty_cards')
 50→          .select('total_points')
 51→          .eq('customer_id', customer.id),
 52→        supabase
 53→          .from('scans')
 54→          .select('id', { count: 'exact', head: true })
 55→          .eq('customer_id', customer.id),
 56→        supabase
 57→          .from('qr_codes')
 58→          .select('id, expires_at, is_active')
 59→          .eq('customer_id', customer.id)
 60→          .eq('qr_type', 'campaign'),
 61→      ]);
 62→
 63→      if (cardsRes.error || scansRes.error || offersRes.error) {
 64→        setError('Impossible de charger les statistiques');
 65→        setLoading(false);
 66→        return;
 67→      }
 68→
 69→      const cards = cardsRes.data ?? [];
 70→      const totalPoints = cards.reduce(
 71→        (sum, c) => sum + (c.total_points ?? 0),
 72→        0
 73→      );
 74→
 75→      // Dernier scan
 76→      const { data: lastScan } = await supabase
 77→        .from('scans')
 78→        .select('scanned_at')
 79→        .eq('customer_id', customer.id)
 80→        .order('scanned_at', { ascending: false })
 81→        .limit(1)
 82→        .maybeSingle();
 83→
 84→      // Offres actives non redemees
 85→      const now = new Date();
 86→      const { data: redemptions } = await supabase
 87→        .from('campaign_redemptions')
 88→        .select('campaign_id')
 89→        .eq('customer_id', customer.id);
 90→
 91→      const redeemedCampaigns = new Set(
 92→        (redemptions ?? []).map((r) => r.campaign_id)
 93→      );
 94→
 95→      // Pour les offres, on doit aussi verifier le campaign_id
 96→      const activeOffers = (offersRes.data ?? []).filter((qr) => {
 97→        if (!qr.is_active) return false;
 98→        if (qr.expires_at && new Date(qr.expires_at) < now) return false;
 99→        return true;
100→      });
101→
102→      // Filtrer les offres deja redemees (on a besoin du campaign_id)
103→      const { data: qrWithCampaign } = await supabase
104→        .from('qr_codes')
105→        .select('campaign_id')
106→        .eq('customer_id', customer.id)
107→        .eq('qr_type', 'campaign')
108→        .eq('is_active', true);
109→
110→      const activeNotRedeemed = (qrWithCampaign ?? []).filter(
111→        (qr) => qr.campaign_id && !redeemedCampaigns.has(qr.campaign_id)
112→      );
113→
114→      setStats({
115→        total_cards: cards.length,
116→        total_points_all: totalPoints,
117→        total_scans: scansRes.count ?? 0,
118→        last_scan_at: lastScan?.scanned_at ?? null,
119→        active_offers: Math.min(activeNotRedeemed.length, activeOffers.length),
120→      });
121→      setLoading(false);
122→    }
123→
124→    fetchStats();
125→  }, [user]);
126→
127→  return { stats, loading, error };
128→}
