  1→import { useState, useEffect } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { QRCode, Campaign } from '@astrolab/shared';
  5→
  6→export interface OfferWithStatus {
  7→  qr_code: QRCode;
  8→  campaign: Campaign;
  9→  status: 'active' | 'expired' | 'redeemed';
 10→  redeemed_at?: string;
 11→}
 12→
 13→interface UseCustomerOffersReturn {
 14→  offers: OfferWithStatus[];
 15→  loading: boolean;
 16→  error: string | null;
 17→}
 18→
 19→export function useCustomerOffers(): UseCustomerOffersReturn {
 20→  const { user } = useAuth();
 21→  const [offers, setOffers] = useState<OfferWithStatus[]>([]);
 22→  const [loading, setLoading] = useState(true);
 23→  const [error, setError] = useState<string | null>(null);
 24→
 25→  useEffect(() => {
 26→    if (!user) {
 27→      setLoading(false);
 28→      return;
 29→    }
 30→
 31→    async function fetchOffers() {
 32→      setLoading(true);
 33→
 34→      const { data: customer } = await supabase
 35→        .from('customers')
 36→        .select('id')
 37→        .eq('profile_id', user!.id)
 38→        .single();
 39→
 40→      if (!customer) {
 41→        setOffers([]);
 42→        setLoading(false);
 43→        return;
 44→      }
 45→
 46→      // QR codes campagne destines a ce customer
 47→      const { data: qrCodes, error: fetchError } = await supabase
 48→        .from('qr_codes')
 49→        .select(
 50→          '*, campaigns!qr_codes_campaign_id_fkey(*)'
 51→        )
 52→        .eq('customer_id', customer.id)
 53→        .eq('qr_type', 'campaign')
 54→        .order('created_at', { ascending: false });
 55→
 56→      if (fetchError) {
 57→        setError('Impossible de charger les offres');
 58→        setLoading(false);
 59→        return;
 60→      }
 61→
 62→      // Recuperer les redemptions du customer
 63→      const { data: redemptions } = await supabase
 64→        .from('campaign_redemptions')
 65→        .select('campaign_id, redeemed_at')
 66→        .eq('customer_id', customer.id);
 67→
 68→      const redemptionMap = new Map(
 69→        (redemptions ?? []).map((r) => [r.campaign_id, r.redeemed_at])
 70→      );
 71→
 72→      const now = new Date();
 73→      const mapped: OfferWithStatus[] = (qrCodes ?? []).map((row) => {
 74→        const campaign = (row as Record<string, unknown>).campaigns as Campaign;
 75→        const qr = row as unknown as QRCode;
 76→        const redeemedAt = campaign ? redemptionMap.get(campaign.id) : undefined;
 77→
 78→        let status: 'active' | 'expired' | 'redeemed' = 'active';
 79→        if (redeemedAt) {
 80→          status = 'redeemed';
 81→        } else if (
 82→          (qr.expires_at && new Date(qr.expires_at) < now) ||
 83→          !qr.is_active
 84→        ) {
 85→          status = 'expired';
 86→        }
 87→
 88→        return {
 89→          qr_code: qr,
 90→          campaign,
 91→          status,
 92→          redeemed_at: redeemedAt ?? undefined,
 93→        };
 94→      });
 95→
 96→      setOffers(mapped);
 97→      setLoading(false);
 98→    }
 99→
100→    fetchOffers();
101→  }, [user]);
102→
103→  return { offers, loading, error };
104→}
