 1→import { useState, useEffect } from 'react';
 2→import { supabase } from '../lib/supabase';
 3→import { useAuth } from './useAuth';
 4→import { getStartOfDay, getStartOfWeek, getStartOfMonth } from '../lib/date-utils';
 5→import type { MerchantStats } from '@astrolab/shared';
 6→
 7→interface UseMerchantStatsReturn {
 8→  stats: MerchantStats;
 9→  loading: boolean;
10→  error: string | null;
11→}
12→
13→const defaultStats: MerchantStats = {
14→  total_clients: 0,
15→  scans_today: 0,
16→  scans_this_week: 0,
17→  scans_this_month: 0,
18→  total_scans: 0,
19→  active_campaigns: 0,
20→  total_redemptions: 0,
21→  avg_visits_per_client: 0,
22→  retention_rate: 0,
23→};
24→
25→export function useMerchantStats(): UseMerchantStatsReturn {
26→  const { user } = useAuth();
27→  const [stats, setStats] = useState<MerchantStats>(defaultStats);
28→  const [loading, setLoading] = useState(true);
29→  const [error, setError] = useState<string | null>(null);
30→
31→  useEffect(() => {
32→    if (!user) { setLoading(false); return; }
33→
34→    async function fetchStats() {
35→      setLoading(true);
36→
37→      const { data: merchant } = await supabase
38→        .from('merchants')
39→        .select('id')
40→        .eq('profile_id', user!.id)
41→        .single();
42→
43→      if (!merchant) { setLoading(false); return; }
44→
45→      const mid = merchant.id;
46→      const today = getStartOfDay().toISOString();
47→      const weekStart = getStartOfWeek().toISOString();
48→      const monthStart = getStartOfMonth().toISOString();
49→
50→      const [clientsRes, scansAllRes, scansTodayRes, scansWeekRes, scansMonthRes, campaignsRes, redemptionsRes] =
51→        await Promise.all([
52→          supabase.from('loyalty_cards').select('customer_id', { count: 'exact', head: true }).eq('merchant_id', mid),
53→          supabase.from('scans').select('customer_id').eq('merchant_id', mid),
54→          supabase.from('scans').select('id', { count: 'exact', head: true }).eq('merchant_id', mid).gte('scanned_at', today),
55→          supabase.from('scans').select('id', { count: 'exact', head: true }).eq('merchant_id', mid).gte('scanned_at', weekStart),
56→          supabase.from('scans').select('id', { count: 'exact', head: true }).eq('merchant_id', mid).gte('scanned_at', monthStart),
57→          supabase.from('campaigns').select('id', { count: 'exact', head: true }).eq('merchant_id', mid).in('status', ['active', 'scheduled']),
58→          supabase.from('campaign_redemptions').select('id', { count: 'exact', head: true }).eq('merchant_id', mid),
59→        ]);
60→
61→      if (clientsRes.error || scansAllRes.error) {
62→        setError('Impossible de charger les statistiques');
63→        setLoading(false);
64→        return;
65→      }
66→
67→      const totalClients = clientsRes.count ?? 0;
68→      const totalScans = scansAllRes.data?.length ?? 0;
69→
70→      // Retention: clients avec > 1 scan
71→      const customerScanCounts = new Map<string, number>();
72→      (scansAllRes.data ?? []).forEach((s) => {
73→        customerScanCounts.set(s.customer_id, (customerScanCounts.get(s.customer_id) ?? 0) + 1);
74→      });
75→      const repeatClients = Array.from(customerScanCounts.values()).filter((c) => c > 1).length;
76→      const uniqueClients = customerScanCounts.size;
77→
78→      setStats({
79→        total_clients: totalClients,
80→        scans_today: scansTodayRes.count ?? 0,
81→        scans_this_week: scansWeekRes.count ?? 0,
82→        scans_this_month: scansMonthRes.count ?? 0,
83→        total_scans: totalScans,
84→        active_campaigns: campaignsRes.count ?? 0,
85→        total_redemptions: redemptionsRes.count ?? 0,
86→        avg_visits_per_client: totalClients > 0 ? Math.round((totalScans / totalClients) * 10) / 10 : 0,
87→        retention_rate: uniqueClients > 0 ? Math.round((repeatClients / uniqueClients) * 100) : 0,
88→      });
89→      setLoading(false);
90→    }
91→
92→    fetchStats();
93→  }, [user]);
94→
95→  return { stats, loading, error };
96→}
