 1→import { useState, useEffect, useCallback } from 'react';
 2→import { supabase } from '../lib/supabase';
 3→import { useAuth } from './useAuth';
 4→import { usePush } from './usePush';
 5→import { getTags } from '../lib/onesignal';
 6→import type { MerchantNotifPref } from '@astrolab/shared';
 7→
 8→interface UseNotificationPreferencesReturn {
 9→  preferences: MerchantNotifPref[];
10→  loading: boolean;
11→  toggleMerchant: (merchantId: string, enabled: boolean) => Promise<void>;
12→}
13→
14→export function useNotificationPreferences(): UseNotificationPreferencesReturn {
15→  const { user } = useAuth();
16→  const { subscribeToMerchant, unsubscribeFromMerchant } = usePush();
17→  const [preferences, setPreferences] = useState<MerchantNotifPref[]>([]);
18→  const [loading, setLoading] = useState(true);
19→
20→  useEffect(() => {
21→    if (!user) {
22→      setLoading(false);
23→      return;
24→    }
25→
26→    async function fetchPreferences() {
27→      setLoading(true);
28→
29→      // Get customer
30→      const { data: customer } = await supabase
31→        .from('customers')
32→        .select('id')
33→        .eq('profile_id', user!.id)
34→        .maybeSingle();
35→
36→      if (!customer) {
37→        setLoading(false);
38→        return;
39→      }
40→
41→      // Get all merchants the customer has a loyalty card with
42→      const { data: cards } = await supabase
43→        .from('loyalty_cards')
44→        .select('merchant_id, merchants!loyalty_cards_merchant_id_fkey(business_name)')
45→        .eq('customer_id', customer.id);
46→
47→      if (!cards || cards.length === 0) {
48→        setLoading(false);
49→        return;
50→      }
51→
52→      // Get current OneSignal tags
53→      const tags = await getTags();
54→
55→      const prefs: MerchantNotifPref[] = cards.map((card) => {
56→        const merchantData = (card as Record<string, unknown>).merchants as {
57→          business_name: string;
58→        } | null;
59→        return {
60→          merchant_id: card.merchant_id,
61→          business_name: merchantData?.business_name ?? 'Commerce',
62→          notifications_enabled: tags[`merchant_${card.merchant_id}`] === 'true',
63→        };
64→      });
65→
66→      setPreferences(prefs);
67→      setLoading(false);
68→    }
69→
70→    fetchPreferences();
71→  }, [user]);
72→
73→  const toggleMerchant = useCallback(
74→    async (merchantId: string, enabled: boolean) => {
75→      if (enabled) {
76→        await subscribeToMerchant(merchantId);
77→      } else {
78→        await unsubscribeFromMerchant(merchantId);
79→      }
80→
81→      setPreferences((prev) =>
82→        prev.map((p) =>
83→          p.merchant_id === merchantId
84→            ? { ...p, notifications_enabled: enabled }
85→            : p
86→        )
87→      );
88→    },
89→    [subscribeToMerchant, unsubscribeFromMerchant]
90→  );
91→
