  1→import { useState, useEffect } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { LoyaltyCard, Scan, CampaignRedemption } from '@astrolab/shared';
  5→
  6→interface ClientProfile {
  7→  full_name: string;
  8→  email: string;
  9→  created_at: string;
 10→}
 11→
 12→interface ScanRow extends Scan {
 13→  merchant_name?: string;
 14→}
 15→
 16→interface RedemptionRow extends CampaignRedemption {
 17→  campaign_title: string;
 18→}
 19→
 20→interface UseMerchantClientDetailReturn {
 21→  client: ClientProfile | null;
 22→  loyaltyCard: LoyaltyCard | null;
 23→  scans: ScanRow[];
 24→  redemptions: RedemptionRow[];
 25→  loading: boolean;
 26→  error: string | null;
 27→}
 28→
 29→export function useMerchantClientDetail(customerId: string | undefined): UseMerchantClientDetailReturn {
 30→  const { user } = useAuth();
 31→  const [client, setClient] = useState<ClientProfile | null>(null);
 32→  const [loyaltyCard, setLoyaltyCard] = useState<LoyaltyCard | null>(null);
 33→  const [scans, setScans] = useState<ScanRow[]>([]);
 34→  const [redemptions, setRedemptions] = useState<RedemptionRow[]>([]);
 35→  const [loading, setLoading] = useState(true);
 36→  const [error, setError] = useState<string | null>(null);
 37→
 38→  useEffect(() => {
 39→    if (!user || !customerId) { setLoading(false); return; }
 40→
 41→    async function fetchDetail() {
 42→      setLoading(true);
 43→
 44→      const { data: merchant } = await supabase
 45→        .from('merchants')
 46→        .select('id')
 47→        .eq('profile_id', user!.id)
 48→        .single();
 49→
 50→      if (!merchant) { setError('Marchand introuvable'); setLoading(false); return; }
 51→
 52→      // Get customer profile
 53→      const { data: customerRow } = await supabase
 54→        .from('customers')
 55→        .select('id, profile_id, profiles!customers_profile_id_fkey(full_name, email, created_at)')
 56→        .eq('id', customerId!)
 57→        .single();
 58→
 59→      if (!customerRow) { setError('Client introuvable'); setLoading(false); return; }
 60→
 61→      const profile = (customerRow as Record<string, unknown>).profiles as {
 62→        full_name: string | null;
 63→        email: string;
 64→        created_at: string;
 65→      } | null;
 66→
 67→      setClient({
 68→        full_name: profile?.full_name ?? 'Client',
 69→        email: profile?.email ?? '',
 70→        created_at: profile?.created_at ?? '',
 71→      });
 72→
 73→      // Loyalty card
 74→      const { data: card } = await supabase
 75→        .from('loyalty_cards')
 76→        .select('*')
 77→        .eq('customer_id', customerId!)
 78→        .eq('merchant_id', merchant.id)
 79→        .maybeSingle();
 80→
 81→      setLoyaltyCard(card as LoyaltyCard | null);
 82→
 83→      // Scans
 84→      const { data: scanRows } = await supabase
 85→        .from('scans')
 86→        .select('*')
 87→        .eq('customer_id', customerId!)
 88→        .eq('merchant_id', merchant.id)
 89→        .order('scanned_at', { ascending: false })
 90→        .limit(50);
 91→
 92→      setScans((scanRows ?? []) as ScanRow[]);
 93→
 94→      // Redemptions
 95→      const { data: redemptionRows } = await supabase
 96→        .from('campaign_redemptions')
 97→        .select('*, campaigns!campaign_redemptions_campaign_id_fkey(title)')
 98→        .eq('customer_id', customerId!)
 99→        .eq('merchant_id', merchant.id)
100→        .order('redeemed_at', { ascending: false });
101→
102→      setRedemptions(
103→        (redemptionRows ?? []).map((r) => ({
104→          ...(r as unknown as CampaignRedemption),
105→          campaign_title:
106→            ((r as Record<string, unknown>).campaigns as { title: string } | null)?.title ?? 'Campagne',
107→        }))
108→      );
109→
110→      setLoading(false);
111→    }
112→
113→    fetchDetail();
114→  }, [user, customerId]);
115→
116→  return { client, loyaltyCard, scans, redemptions, loading, error };
117→}
