  1→import { useState, useEffect } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import { format, subDays, subWeeks, startOfWeek } from 'date-fns';
  5→import type { DailyScanData, WeeklyNewClientData } from '@astrolab/shared';
  6→
  7→interface UseMerchantChartDataReturn {
  8→  dailyScans: DailyScanData[];
  9→  weeklyNewClients: WeeklyNewClientData[];
 10→  loading: boolean;
 11→  error: string | null;
 12→}
 13→
 14→export function useMerchantChartData(): UseMerchantChartDataReturn {
 15→  const { user } = useAuth();
 16→  const [dailyScans, setDailyScans] = useState<DailyScanData[]>([]);
 17→  const [weeklyNewClients, setWeeklyNewClients] = useState<WeeklyNewClientData[]>([]);
 18→  const [loading, setLoading] = useState(true);
 19→  const [error, setError] = useState<string | null>(null);
 20→
 21→  useEffect(() => {
 22→    if (!user) { setLoading(false); return; }
 23→
 24→    async function fetchChartData() {
 25→      setLoading(true);
 26→
 27→      const { data: merchant } = await supabase
 28→        .from('merchants')
 29→        .select('id')
 30→        .eq('profile_id', user!.id)
 31→        .single();
 32→
 33→      if (!merchant) { setLoading(false); return; }
 34→
 35→      const thirtyDaysAgo = subDays(new Date(), 30).toISOString();
 36→      const twelveWeeksAgo = subWeeks(new Date(), 12).toISOString();
 37→
 38→      const [scansRes, cardsRes] = await Promise.all([
 39→        supabase
 40→          .from('scans')
 41→          .select('scanned_at')
 42→          .eq('merchant_id', merchant.id)
 43→          .gte('scanned_at', thirtyDaysAgo)
 44→          .order('scanned_at', { ascending: true }),
 45→        supabase
 46→          .from('loyalty_cards')
 47→          .select('created_at')
 48→          .eq('merchant_id', merchant.id)
 49→          .gte('created_at', twelveWeeksAgo)
 50→          .order('created_at', { ascending: true }),
 51→      ]);
 52→
 53→      if (scansRes.error || cardsRes.error) {
 54→        setError('Impossible de charger les graphiques');
 55→        setLoading(false);
 56→        return;
 57→      }
 58→
 59→      // Scans par jour (30 derniers jours)
 60→      const dayMap = new Map<string, number>();
 61→      for (let i = 29; i >= 0; i--) {
 62→        const d = format(subDays(new Date(), i), 'yyyy-MM-dd');
 63→        dayMap.set(d, 0);
 64→      }
 65→      (scansRes.data ?? []).forEach((s) => {
 66→        const d = format(new Date(s.scanned_at), 'yyyy-MM-dd');
 67→        dayMap.set(d, (dayMap.get(d) ?? 0) + 1);
 68→      });
 69→      setDailyScans(
 70→        Array.from(dayMap.entries()).map(([date, count]) => ({
 71→          date: format(new Date(date), 'dd/MM'),
 72→          count,
 73→        }))
 74→      );
 75→
 76→      // Nouveaux clients par semaine (12 semaines)
 77→      const weekMap = new Map<string, number>();
 78→      for (let i = 11; i >= 0; i--) {
 79→        const ws = startOfWeek(subWeeks(new Date(), i), { weekStartsOn: 1 });
 80→        const key = format(ws, 'yyyy-MM-dd');
 81→        weekMap.set(key, 0);
 82→      }
 83→      (cardsRes.data ?? []).forEach((c) => {
 84→        const ws = startOfWeek(new Date(c.created_at), { weekStartsOn: 1 });
 85→        const key = format(ws, 'yyyy-MM-dd');
 86→        if (weekMap.has(key)) {
 87→          weekMap.set(key, (weekMap.get(key) ?? 0) + 1);
 88→        }
 89→      });
 90→      setWeeklyNewClients(
 91→        Array.from(weekMap.entries()).map(([week, count]) => ({
 92→          week: format(new Date(week), 'dd/MM'),
 93→          count,
 94→        }))
 95→      );
 96→
 97→      setLoading(false);
 98→    }
 99→
100→    fetchChartData();
101→  }, [user]);
102→
103→  return { dailyScans, weeklyNewClients, loading, error };
104→}
