 46→  selected: TargetAudience;
 47→  onSelect: (audience: TargetAudience) => void;
 48→  getCount: (audience: TargetAudience) => Promise<number>;
 49→}
 50→
 51→export function AudienceSelector({ selected, onSelect, getCount }: AudienceSelectorProps) {
 52→  const [counts, setCounts] = useState<Record<string, number | null>>({});
 53→  const [loadingAudience, setLoadingAudience] = useState<string | null>(null);
 54→
 55→  useEffect(() => {
 56→    async function loadCount() {
 57→      if (counts[selected] !== undefined) return;
 58→
 59→      setLoadingAudience(selected);
 60→      const count = await getCount(selected);
 61→      setCounts((prev) => ({ ...prev, [selected]: count }));
 62→      setLoadingAudience(null);
 63→    }
 64→
 65→    loadCount();
 66→  }, [selected, getCount, counts]);
 67→
 68→  return (
 69→    <div className="space-y-3">
 70→      {audienceOptions.map((option) => {
 71→        const isSelected = selected === option.value;
 72→        const count = counts[option.value];
 73→        const isLoading = loadingAudience === option.value;
 74→
 75→        return (
 76→          <label
 77→            key={option.value}
 78→            className={`flex cursor-pointer items-center gap-4 rounded-lg border-2 p-4 transition-colors ${
 79→              isSelected
 80→                ? 'border-[var(--color-primary)] bg-indigo-50'
 81→                : 'border-slate-200 hover:border-slate-300'
 82→            }`}
 83→          >
 84→            <input
 85→              type="radio"
 86→              name="audience"
 87→              value={option.value}
 88→              checked={isSelected}
 89→              onChange={() => onSelect(option.value)}
 90→              className="sr-only"
 91→            />
 92→            <span className="text-2xl">{option.icon}</span>
 93→            <div className="flex-1">
 94→              <p className="text-sm font-semibold text-[var(--color-text)]">
 95→                {option.label}
 96→              </p>
 97→              <p className="text-xs text-[var(--color-text-muted)]">
 98→                {option.description}
 99→              </p>
100→            </div>
101→            <div className="text-right">
102→              {isSelected && isLoading ? (
103→                <Spinner />
104→              ) : count !== null && count !== undefined ? (
105→                <span className="text-lg font-bold text-[var(--color-primary)]">
106→                  {count}
107→                </span>
108→              ) : (
109→                <span className="text-sm text-[var(--color-text-muted)]">—</span>
110→              )}
111→              {count !== null && count !== undefined && (
112→                <p className="text-[10px] text-[var(--color-text-muted)]">clients</p>
113→              )}
114→            </div>
115→          </label>
116→        );
117→      })}
118→    </div>
119→  );
120→}
