 1→import { useState, useEffect, useRef } from 'react';
 2→
 3→interface SearchInputProps {
 4→  value: string;
 5→  onChange: (value: string) => void;
 6→  placeholder?: string;
 7→  debounceMs?: number;
 8→}
 9→
10→export function SearchInput({
11→  value,
12→  onChange,
13→  placeholder = 'Rechercher...',
14→  debounceMs = 300,
15→}: SearchInputProps) {
16→  const [local, setLocal] = useState(value);
17→  const timerRef = useRef<ReturnType<typeof setTimeout>>();
18→
19→  useEffect(() => {
20→    setLocal(value);
21→  }, [value]);
22→
23→  function handleChange(val: string) {
24→    setLocal(val);
25→    clearTimeout(timerRef.current);
26→    timerRef.current = setTimeout(() => onChange(val), debounceMs);
27→  }
28→
29→  return (
30→    <div className="relative">
31→      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--color-text-muted)]">
32→        🔍
33→      </span>
34→      <input
35→        type="text"
36→        value={local}
37→        onChange={(e) => handleChange(e.target.value)}
38→        placeholder={placeholder}
39→        className="w-full rounded-lg border border-slate-200 bg-[var(--color-surface)] py-2.5 pl-10 pr-10 text-sm text-[var(--color-text)] outline-none transition-colors focus:border-[var(--color-primary)] focus:ring-1 focus:ring-[var(--color-primary)]"
40→      />
41→      {local && (
42→        <button
43→          onClick={() => handleChange('')}
44→          className="absolute right-3 top-1/2 -translate-y-1/2 text-[var(--color-text-muted)] hover:text-[var(--color-text)]"
45→        >
46→          ✕
47→        </button>
48→      )}
49→    </div>
50→  );
51→}
